import {Icon as LeafletIcon} from "leaflet";
import { Icon } from '@mui/material';

export const VFO1Icon = ({ size = 28, ...props }) => {
    return (
        <Icon {...props}>
            <img
                src={"data:image/png;base64,"}
                alt="VFO1 icon"
                style={{ width: size, height: size }}
            />
        </Icon>
    );
};

